/**
 * Graph tidying for people who dropped fifty nodes and now regret it.
 *
 * We read real Comfy links from {@link LLink.origin_id} out to {@link LLink.target_id} in and
 * try to draw the story left to right like a comic strip. Cycles are the plot twist: Tarjan
 * shrinks them so the DAG stops pretending it is a tree, then we layer that honest graph.
 *
 * Reroutes and friends ride along so your spaghetti does not snap mid chain. If you only
 * selected part of the mess, nodes outside still whisper their rank through incoming wires
 * from the left. Roots with boring outputs can get nudged right when the exciting stuff
 * already lives in column two or beyond, which keeps loaders humble and samplers in frame.
 */

import type { LGraph } from '@/lib/litegraph/src/LGraph'
import type { LGraphCanvas } from '@/lib/litegraph/src/LGraphCanvas'
import type { LLink } from '@/lib/litegraph/src/LLink'
import { LGraphNode } from '@/lib/litegraph/src/LGraphNode'
import { LiteGraph } from '@/lib/litegraph/src/litegraph'
import { getAllNestedItems } from '@/lib/litegraph/src/utils/collections'

const H_GAP = 80
const V_GAP = 36
const EXTERNAL_RANK_X_SCALE = 420
const BARYCENTER_ITERS = 6
/** Roots only slide right when their kids already party at this layer or deeper. */
const PULL_ROOT_MIN_DIRECT_LAYER = 2

/** Ghosts and pins sit this one out. Virtual nodes join the conga line so reroutes count. */
export function isNodeAutoLayoutable(node: LGraphNode): boolean {
  if (node.flags?.ghost) return false
  if (node.flags?.pinned) return false
  return true
}

function nodeKey(n: LGraphNode): string {
  return String(n.id)
}

function isLinkConnectable(link: LLink): boolean {
  return !link.isFloating
}

function collectEdges(
  graph: LGraph,
  nodeSet: Set<LGraphNode>
): Array<[LGraphNode, LGraphNode]> {
  const edges: Array<[LGraphNode, LGraphNode]> = []
  for (const link of graph.links.values()) {
    if (!isLinkConnectable(link)) continue
    const from = graph.getNodeById(link.origin_id)
    const to = graph.getNodeById(link.target_id)
    if (!from || !to) continue
    if (!nodeSet.has(from) || !nodeSet.has(to)) continue
    edges.push([from, to])
  }
  return edges
}

function externalInputBaseline(
  graph: LGraph,
  nodeSet: Set<LGraphNode>
): Map<string, number> {
  const baseline = new Map<string, number>()
  for (const n of nodeSet) {
    let b = 0
    for (const link of graph.links.values()) {
      if (!isLinkConnectable(link)) continue
      if (link.target_id !== n.id) continue
      const pred = graph.getNodeById(link.origin_id)
      if (!pred || nodeSet.has(pred)) continue
      const rank = Math.max(
        0,
        Math.round(pred.pos[0] / EXTERNAL_RANK_X_SCALE)
      )
      b = Math.max(b, rank + 1)
    }
    baseline.set(nodeKey(n), b)
  }
  return baseline
}

/** Tarjan — returns SCCs as lists of node keys (each SCC is one “super-node” in the condensation DAG). */
function tarjanStrongComponents(
  keys: string[],
  edgePairs: Array<[string, string]>
): string[][] {
  const keySet = new Set(keys)
  const adj = new Map<string, string[]>()
  for (const k of keys) adj.set(k, [])
  for (const [a, b] of edgePairs) {
    if (keySet.has(a) && keySet.has(b)) adj.get(a)!.push(b)
  }

  let idx = 0
  const stack: string[] = []
  const indices = new Map<string, number>()
  const lowlink = new Map<string, number>()
  const onStack = new Set<string>()
  const sccs: string[][] = []

  function strongconnect(v: string): void {
    indices.set(v, idx)
    lowlink.set(v, idx)
    idx++
    stack.push(v)
    onStack.add(v)

    for (const w of adj.get(v) ?? []) {
      if (!indices.has(w)) {
        strongconnect(w)
        lowlink.set(v, Math.min(lowlink.get(v)!, lowlink.get(w)!))
      } else if (onStack.has(w)) {
        lowlink.set(v, Math.min(lowlink.get(v)!, indices.get(w)!))
      }
    }

    if (lowlink.get(v) === indices.get(v)) {
      const comp: string[] = []
      while (stack.length) {
        const w = stack.pop()!
        onStack.delete(w)
        comp.push(w)
        if (w === v) break
      }
      sccs.push(comp)
    }
  }

  for (const k of keys) {
    if (!indices.has(k)) strongconnect(k)
  }
  return sccs
}

function compressLayerRanks(layer: Map<string, number>): void {
  const sorted = [...new Set(layer.values())].sort((a, b) => a - b)
  const remap = new Map(sorted.map((v, i) => [v, i]))
  for (const k of [...layer.keys()]) {
    layer.set(k, remap.get(layer.get(k)!)!)
  }
}

/** Longest path on condensation DAG; then merge baseline and enforce strict order between SCCs. */
function assignLayersFromCondensation(
  nodes: LGraphNode[],
  edges: Array<[LGraphNode, LGraphNode]>,
  baseline: Map<string, number> | undefined
): Map<string, number> {
  const keys = nodes.map(nodeKey)
  const edgePairs = edges.map(([a, b]) => [nodeKey(a), nodeKey(b)] as [string, string])

  const sccs = tarjanStrongComponents(keys, edgePairs)
  const compId = new Map<string, number>()
  sccs.forEach((comp, i) => {
    for (const k of comp) compId.set(k, i)
  })

  const c = sccs.length
  const adj = Array.from({ length: c }, () => [] as number[])
  const indeg = new Array(c).fill(0)
  const seen = new Set<string>()

  for (const [a, b] of edgePairs) {
    const ia = compId.get(a)!
    const ib = compId.get(b)!
    if (ia === ib) continue
    const sig = `${ia}|${ib}`
    if (seen.has(sig)) continue
    seen.add(sig)
    adj[ia].push(ib)
    indeg[ib]++
  }

  const queue = indeg.map((d, i) => (d === 0 ? i : -1)).filter((i) => i >= 0)
  const topo: number[] = []
  const rem = [...indeg]
  while (queue.length) {
    const u = queue.shift()!
    topo.push(u)
    for (const v of adj[u]) {
      rem[v]--
      if (rem[v] === 0) queue.push(v)
    }
  }

  const rank = new Array(c).fill(0)
  for (const u of topo) {
    for (const v of adj[u]) {
      rank[v] = Math.max(rank[v], rank[u] + 1)
    }
  }

  const layer = new Map<string, number>()
  for (const n of nodes) {
    const k = nodeKey(n)
    const r = rank[compId.get(k)!]
    layer.set(k, Math.max(r, baseline?.get(k) ?? 0))
  }

  const preds = new Map<string, Set<string>>()
  const succs = new Map<string, Set<string>>()
  for (const k of keys) {
    preds.set(k, new Set())
    succs.set(k, new Set())
  }
  for (const [a, b] of edgePairs) {
    succs.get(a)!.add(b)
    preds.get(b)!.add(a)
  }

  function enforceForwardLayers(): void {
    for (let pass = 0; pass < keys.length + edgePairs.length + 4; pass++) {
      let changed = false
      for (const [u, v] of edges) {
        const uk = nodeKey(u)
        const vk = nodeKey(v)
        if (compId.get(uk) === compId.get(vk)) continue
        const lu = layer.get(uk) ?? 0
        const lv = layer.get(vk) ?? 0
        if (lv <= lu) {
          layer.set(vk, lu + 1)
          changed = true
        }
      }
      if (!changed) break
    }
  }

  enforceForwardLayers()

  /** Deepest layer among nodes reachable from k via forward edges (excluding k). */
  function maxDownstreamLayer(k: string): number {
    let best = -1
    const seen = new Set<string>()
    const stack = [...(succs.get(k) ?? [])]
    while (stack.length) {
      const w = stack.pop()!
      if (seen.has(w)) continue
      seen.add(w)
      const lw = layer.get(w) ?? 0
      if (lw > best) best = lw
      for (const t of succs.get(w) ?? []) stack.push(t)
    }
    return best
  }

  for (const k of keys) {
    if ((preds.get(k)?.size ?? 0) > 0) continue
    const outs = succs.get(k)!
    if (!outs.size) continue
    let minSuccLayer = Infinity
    for (const v of outs) {
      minSuccLayer = Math.min(minSuccLayer, layer.get(v) ?? 0)
    }
    if (minSuccLayer < PULL_ROOT_MIN_DIRECT_LAYER) continue

    const downMax = maxDownstreamLayer(k)
    if (downMax < 0) continue
    const want = downMax - 1
    const cur = layer.get(k) ?? 0
    const b = baseline?.get(k) ?? 0
    layer.set(k, Math.max(b, cur, want))
  }

  enforceForwardLayers()

  compressLayerRanks(layer)
  return layer
}

function groupNodesByLayer(
  nodes: LGraphNode[],
  layer: Map<string, number>
): { byLayer: Map<number, LGraphNode[]>; maxLayer: number } {
  const byLayer = new Map<number, LGraphNode[]>()
  let maxLayer = 0
  for (const n of nodes) {
    const L = layer.get(nodeKey(n)) ?? 0
    maxLayer = Math.max(maxLayer, L)
    if (!byLayer.has(L)) byLayer.set(L, [])
    byLayer.get(L)!.push(n)
  }
  return { byLayer, maxLayer }
}

function orderIndexMap(byLayer: Map<number, LGraphNode[]>): Map<string, number> {
  const m = new Map<string, number>()
  for (const [, arr] of byLayer) {
    arr.forEach((n, i) => m.set(nodeKey(n), i))
  }
  return m
}

function barycenterDown(
  byLayer: Map<number, LGraphNode[]>,
  maxLayer: number,
  preds: Map<string, Set<string>>
): void {
  for (let L = 1; L <= maxLayer; L++) {
    const row = byLayer.get(L)
    const below = byLayer.get(L - 1)
    if (!row?.length || !below?.length) continue
    const idx = orderIndexMap(byLayer)
    const belowLen = below.length
    row.sort((a, b) => {
      const bc = (n: LGraphNode) => {
        const ps = [...(preds.get(nodeKey(n)) ?? [])]
        if (!ps.length) return -1
        let s = 0
        let c = 0
        for (const pk of ps) {
          const j = idx.get(pk)
          if (j !== undefined) {
            s += j
            c++
          }
        }
        return c ? s / c : belowLen * 0.5
      }
      const d = bc(a) - bc(b)
      if (d !== 0) return d
      return String(a.id).localeCompare(String(b.id), undefined, {
        numeric: true
      })
    })
  }
}

function barycenterUp(
  byLayer: Map<number, LGraphNode[]>,
  maxLayer: number,
  succs: Map<string, Set<string>>
): void {
  for (let L = maxLayer - 1; L >= 0; L--) {
    const row = byLayer.get(L)
    const above = byLayer.get(L + 1)
    if (!row?.length || !above?.length) continue
    const idx = orderIndexMap(byLayer)
    const aboveLen = above.length
    row.sort((a, b) => {
      const bc = (n: LGraphNode) => {
        const ss = [...(succs.get(nodeKey(n)) ?? [])]
        if (!ss.length) return -1
        let s = 0
        let c = 0
        for (const sk of ss) {
          const j = idx.get(sk)
          if (j !== undefined) {
            s += j
            c++
          }
        }
        return c ? s / c : aboveLen * 0.5
      }
      const d = bc(a) - bc(b)
      if (d !== 0) return d
      return String(a.id).localeCompare(String(b.id), undefined, {
        numeric: true
      })
    })
  }
}

function buildPredSuccMaps(
  edges: Array<[LGraphNode, LGraphNode]>
): {
  preds: Map<string, Set<string>>
  succs: Map<string, Set<string>>
} {
  const preds = new Map<string, Set<string>>()
  const succs = new Map<string, Set<string>>()
  for (const [a, b] of edges) {
    const ak = nodeKey(a)
    const bk = nodeKey(b)
    if (!succs.has(ak)) succs.set(ak, new Set())
    succs.get(ak)!.add(bk)
    if (!preds.has(bk)) preds.set(bk, new Set())
    preds.get(bk)!.add(ak)
  }
  return { preds, succs }
}

function reduceCrossings(
  nodes: LGraphNode[],
  edges: Array<[LGraphNode, LGraphNode]>,
  layer: Map<string, number>
): Map<number, LGraphNode[]> {
  const { preds, succs } = buildPredSuccMaps(edges)
  const { byLayer, maxLayer } = groupNodesByLayer(nodes, layer)

  for (const [, arr] of byLayer) {
    arr.sort(
      (a, b) =>
        a.pos[1] - b.pos[1] ||
        String(a.id).localeCompare(String(b.id), undefined, { numeric: true })
    )
  }

  for (let i = 0; i < BARYCENTER_ITERS; i++) {
    barycenterDown(byLayer, maxLayer, preds)
    barycenterUp(byLayer, maxLayer, succs)
  }

  return byLayer
}

function nodeColumnSize(n: LGraphNode): { w: number; h: number } {
  try {
    n.updateArea()
  } catch {
    /* ignore */
  }
  const [, , bw, bh] = n.boundingRect
  const w = bw > 0 ? bw : n.size[0]
  const title = LiteGraph.NODE_TITLE_HEIGHT
  const h = (bh > 0 ? bh : n.size[1] + title) || title + 40
  return { w, h }
}

function computePositionsFromOrder(
  byLayer: Map<number, LGraphNode[]>,
  maxLayer: number,
  originX: number,
  originY: number
): Map<string, { x: number; y: number }> {
  const out = new Map<string, { x: number; y: number }>()
  let curX = originX
  for (let L = 0; L <= maxLayer; L++) {
    const col = byLayer.get(L)
    if (!col?.length) continue
    let maxW = 0
    let curY = originY
    for (const n of col) {
      const { w, h } = nodeColumnSize(n)
      maxW = Math.max(maxW, w)
      out.set(nodeKey(n), { x: curX, y: curY })
      curY += h + V_GAP
    }
    curX += maxW + H_GAP
  }
  return out
}

/**
 * Second pass: make columns look like they talk to each other instead of random skyscrapers.
 * Column zero stacks from originY. Later columns scoot their whole block so its vertical
 * middle hugs the median of predecessor centers that already live in earlier layers, which
 * is how you get “feeds here, consumers politely beside” instead of “everything hugging the top”.
 */
function assignVerticalByLayerAnchors(
  nodes: LGraphNode[],
  edges: Array<[LGraphNode, LGraphNode]>,
  byLayer: Map<number, LGraphNode[]>,
  maxLayer: number,
  layer: Map<string, number>,
  pos: Map<string, { x: number; y: number }>,
  originY: number
): void {
  const { preds } = buildPredSuccMaps(edges)
  const keyToNode = new Map(nodes.map((n) => [nodeKey(n), n]))

  const predCentersFromLowerLayers = (
    n: LGraphNode,
    nLayer: number
  ): number[] => {
    const ys: number[] = []
    for (const pk of preds.get(nodeKey(n)) ?? []) {
      const pl = layer.get(pk)
      if (pl === undefined || pl >= nLayer) continue
      const p = pos.get(pk)
      const pn = keyToNode.get(pk)
      if (p && pn) {
        const { h } = nodeColumnSize(pn)
        ys.push(p.y + h * 0.5)
      }
    }
    return ys
  }

  const medianSortKey = (n: LGraphNode): number => {
    const nL = layer.get(nodeKey(n)) ?? 0
    const ys = predCentersFromLowerLayers(n, nL)
    if (!ys.length) return pos.get(nodeKey(n))!.y
    ys.sort((a, b) => a - b)
    return ys[Math.floor((ys.length - 1) / 2)]!
  }

  const allPredCentersForColumn = (
    row: LGraphNode[],
    columnLayer: number
  ): number[] => {
    const ys: number[] = []
    for (const n of row) {
      ys.push(...predCentersFromLowerLayers(n, columnLayer))
    }
    return ys
  }

  const columnStackHeight = (row: LGraphNode[]): number => {
    let t = 0
    for (const n of row) t += nodeColumnSize(n).h + V_GAP
    return Math.max(0, t - V_GAP)
  }

  for (let L = 0; L <= maxLayer; L++) {
    const row = byLayer.get(L)
    if (!row?.length) continue

    row.sort((a, b) => {
      const d = medianSortKey(a) - medianSortKey(b)
      if (d !== 0) return d
      return (
        pos.get(nodeKey(a))!.y - pos.get(nodeKey(b))!.y ||
        String(a.id).localeCompare(String(b.id), undefined, { numeric: true })
      )
    })

    const x0 = pos.get(nodeKey(row[0]))!.x
    let startY = originY

    if (L > 0) {
      const centers = allPredCentersForColumn(row, L)
      if (centers.length) {
        centers.sort((a, b) => a - b)
        const anchor =
          centers[Math.floor((centers.length - 1) / 2)]!
        const hStack = columnStackHeight(row)
        startY = anchor - hStack * 0.5
      }
      startY = Math.max(originY, startY)
    }

    let curY = startY
    for (const n of row) {
      const { h } = nodeColumnSize(n)
      pos.set(nodeKey(n), { x: x0, y: curY })
      curY += h + V_GAP
    }
  }
}

function countLayoutableInGraph(graph: LGraph): number {
  let c = 0
  for (const n of graph._nodes) {
    if (isNodeAutoLayoutable(n)) c++
  }
  return c
}

export function runExperimentalAutoLayout(options: {
  graph: LGraph
  canvas: LGraphCanvas
  nodes: LGraphNode[]
}): boolean {
  const { graph, canvas, nodes } = options
  if (!nodes.length) return false

  const nodeSet = new Set(nodes)
  const edges = collectEdges(graph, nodeSet)
  const partial = nodes.length < countLayoutableInGraph(graph)
  const baseline = partial ? externalInputBaseline(graph, nodeSet) : undefined

  const layer = assignLayersFromCondensation(nodes, edges, baseline)
  const { maxLayer } = groupNodesByLayer(nodes, layer)
  const byLayer = reduceCrossings(nodes, edges, layer)

  const originX = Math.min(...nodes.map((n) => n.pos[0]))
  const originY = Math.min(...nodes.map((n) => n.pos[1]))
  const positions = computePositionsFromOrder(
    byLayer,
    maxLayer,
    originX,
    originY
  )
  assignVerticalByLayerAnchors(
    nodes,
    edges,
    byLayer,
    maxLayer,
    layer,
    positions,
    originY
  )

  graph.beforeChange()
  try {
    for (const n of nodes) {
      const p = positions.get(nodeKey(n))
      if (p) n.setPos(p.x, p.y)
    }
  } finally {
    graph.afterChange()
  }
  canvas.setDirty(true, true)
  return true
}

function collectSelectedLayoutableNodes(
  canvas: LGraphCanvas
): LGraphNode[] {
  const nested = getAllNestedItems(canvas.selectedItems)
  return [...nested].filter(
    (item): item is LGraphNode =>
      item instanceof LGraphNode && isNodeAutoLayoutable(item)
  )
}

/**
 * Brain of the L key: pick the selection if it has layoutable meat, else hug the entire graph.
 */
export function runSmartAutoLayout(graph: LGraph, canvas: LGraphCanvas): boolean {
  const selected = collectSelectedLayoutableNodes(canvas)
  const nodes =
    selected.length > 0
      ? selected
      : graph._nodes.filter(isNodeAutoLayoutable)
  if (!nodes.length) return false
  return runExperimentalAutoLayout({ graph, canvas, nodes })
}
