<template>
  <div>
    <!--
    UnloadWindowConfirmDialog: This component does not render
    anything visible. It is used to confirm the user wants to
    close the window, and if they do, it will call the
    beforeunload event.
    -->
  </div>
</template>

<script setup lang="ts">
import { onBeforeUnmount, onMounted } from 'vue'

import { electronAPI } from '@/utils/envUtil'
import { useSettingStore } from '@/platform/settings/settingStore'
import { useWorkflowStore } from '@/platform/workflow/management/stores/workflowStore'

const settingStore = useSettingStore()
const workflowStore = useWorkflowStore()

const handleBeforeUnload = (event: BeforeUnloadEvent) => {
  if (
    !settingStore.get('Comfy.Window.UnloadConfirmation') ||
    workflowStore.modifiedWorkflows.length === 0
  ) {
    return undefined
  }

  event.preventDefault()
  event.returnValue = ''
  return ''
}

onMounted(() => {
  // Electron shell (incl. builds where __DISTRIBUTION__ is not "desktop"): beforeunload +
  // preventDefault blocks window close with no dialog. Skip here; shell can handle unsaved state.
  if (electronAPI()) return
  window.addEventListener('beforeunload', handleBeforeUnload)
})

onBeforeUnmount(() => {
  if (electronAPI()) return
  window.removeEventListener('beforeunload', handleBeforeUnload)
})
</script>
