import { hsvaToHex } from '@/utils/colorUtil'
import type { ColorOption } from '@/lib/litegraph/src/interfaces'
import { pairFromAccentHex } from '@/utils/nodeColorApply'

export interface SwatchPair {
  color: string
  bgcolor: string
  /** LiteGraph preset key when from classic palette */
  presetKey?: string
}

export function swatchesFromLitegraphPresets(
  presets: Record<string, ColorOption>
): SwatchPair[] {
  return Object.entries(presets).map(([presetKey, opt]) => ({
    color: opt.color,
    bgcolor: opt.bgcolor,
    presetKey
  }))
}

/** Dense grid similar to DCC color racks: 8×5 hues + 8-step grayscale. */
export function buildGeneratedSwatchGrid(): SwatchPair[] {
  const out: SwatchPair[] = []
  const cols = 8
  const rows = 5
  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      const h = (c / cols) * 360
      const s = 28 + (r / Math.max(1, rows - 1)) * 67
      const v = 52 - r * 3
      const hex = hsvaToHex({ h, s, v, a: 100 })
      out.push(pairFromAccentHex(hex))
    }
  }
  for (let i = 0; i < cols; i++) {
    const v = (i / (cols - 1)) * 85 + 8
    const hex = hsvaToHex({ h: 0, s: 0, v, a: 100 })
    out.push(pairFromAccentHex(hex))
  }
  return out
}
