<template>
  <div
    v-show="paletteOpen"
    class="pointer-events-auto fixed right-[248px] bottom-[220px] z-[1100] flex w-[min(calc(100vw-24px),220px)] flex-col overflow-hidden rounded-sm border border-interface-stroke bg-comfy-menu-bg/95 text-sm shadow-interface backdrop-blur-sm"
    data-testid="node-sticker-palette-panel"
    @pointerdown.stop
    @mousedown.stop
  >
    <div
      class="flex items-center justify-between gap-2 border-b border-interface-stroke px-2 py-1.5"
    >
      <span class="text-node-component-fg truncate text-xs font-medium">{{
        $t('nodeStickerPalette.title')
      }}</span>
      <button
        type="button"
        class="hover:text-node-component-fg rounded-sm p-0.5 text-muted-foreground hover:bg-component-node-background"
        :aria-label="$t('g.close')"
        @click="stickerStore.closePalette()"
      >
        <i class="icon-[lucide--x] size-4" />
      </button>
    </div>

    <p class="px-2 pt-1.5 text-[10px] leading-snug text-muted-foreground">
      {{ $t('nodeStickerPalette.hint') }}
    </p>

    <div v-if="!hasSelection" class="px-2 pb-1 text-[10px] text-amber-600 dark:text-amber-400">
      {{ $t('nodeStickerPalette.noSelection') }}
    </div>

    <div class="grid grid-cols-3 gap-1.5 px-2 pt-1 pb-2">
      <button
        type="button"
        :disabled="canvasReadOnly || !hasSelection"
        class="flex flex-col items-center gap-0.5 rounded-sm border border-interface-stroke p-1.5 text-[10px] hover:bg-component-node-background disabled:opacity-40"
        @pointerdown.prevent.stop="onPickSticker(undefined)"
      >
        <i class="icon-[lucide--circle-off] size-6 text-muted-foreground" />
        {{ $t('nodeStickerPalette.clear') }}
      </button>
      <button
        v-for="id in NODE_STICKER_IDS"
        :key="id"
        type="button"
        :disabled="canvasReadOnly || !hasSelection"
        class="flex flex-col items-center gap-0.5 rounded-sm border border-interface-stroke p-1.5 text-[10px] hover:bg-component-node-background disabled:opacity-40"
        @pointerdown.prevent.stop="onPickSticker(id)"
      >
        <i
          :class="NODE_STICKER_ICON_CLASS[id]"
          class="size-6 text-amber-400 dark:text-amber-300"
        />
        {{ $t(`nodeStickerPalette.stickers.${id}`) }}
      </button>
    </div>

    <div
      class="border-t border-interface-stroke px-2 pb-2 pt-2 text-[10px] text-muted-foreground"
    >
      <label class="mb-1 block font-medium text-node-component-fg">{{
        $t('nodeStickerPalette.sizeLabel')
      }}</label>
      <div class="flex items-center gap-2">
        <input
          type="range"
          class="h-1.5 flex-1 cursor-pointer accent-primary"
          min="0.75"
          max="2.5"
          step="0.05"
          :value="stickerScale"
          :aria-label="$t('nodeStickerPalette.sizeLabel')"
          @input="onStickerScaleInput"
        />
        <span
          class="w-10 shrink-0 text-right tabular-nums text-[10px] text-muted-foreground"
          >{{ stickerScaleLabel }}</span
        >
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { storeToRefs } from 'pinia'
import { computed, ref, watch } from 'vue'

import type { LGraphNode } from '@/lib/litegraph/src/litegraph'
import { useNodeStickerApply } from '@/composables/graph/useNodeStickerApply'
import { useCanvasStore } from '@/renderer/core/canvas/canvasStore'
import { app } from '@/scripts/app'
import { useNodeStickerPaletteStore } from '@/stores/nodeStickerPaletteStore'
import {
  NODE_STICKER_ICON_CLASS,
  NODE_STICKER_IDS,
  type NodeStickerId
} from '@/constants/nodeStickers'
import { getSelectedLGraphNodesForPalette } from '@/utils/nodeColorPaletteSelection'

const stickerStore = useNodeStickerPaletteStore()
const { paletteOpen, stickerScale } = storeToRefs(stickerStore)

const stickerScaleLabel = computed(() =>
  Number(stickerScale.value).toFixed(2)
)

function onStickerScaleInput(e: Event) {
  const raw = (e.target as HTMLInputElement).value
  const v = Number.parseFloat(raw)
  if (!Number.isFinite(v)) return
  stickerStore.stickerScale = Math.min(2.5, Math.max(0.75, v))
}
const canvasStore = useCanvasStore()
const { selectedItems } = storeToRefs(canvasStore)
const { applyGfvStickerToNodes } = useNodeStickerApply()

/** When the panel steals focus, selection can clear before click; keep last non-empty set. */
const snapshotNodeIds = ref<string[]>([])

const canvasReadOnly = computed(() => app.canvas?.state.readOnly ?? false)

function resolveTargetNodes(): LGraphNode[] {
  void selectedItems.value
  const fresh = getSelectedLGraphNodesForPalette(app.canvas)
  if (fresh.length) return fresh
  const g = app.canvas?.graph
  if (!g || !snapshotNodeIds.value.length) return []
  const out: LGraphNode[] = []
  for (const sid of snapshotNodeIds.value) {
    const byStr = g.getNodeById(sid)
    const byNum = g.getNodeById(Number(sid))
    const n = byStr ?? byNum
    if (n) out.push(n)
  }
  return out
}

watch(
  [paletteOpen, selectedItems],
  () => {
    if (!paletteOpen.value) return
    const nodes = getSelectedLGraphNodesForPalette(app.canvas)
    if (nodes.length) {
      snapshotNodeIds.value = nodes.map((n) => String(n.id))
    }
  },
  { deep: true }
)

const hasSelection = computed(() => resolveTargetNodes().length > 0)

function onPickSticker(id: NodeStickerId | undefined) {
  if (canvasReadOnly.value) return
  const sel = resolveTargetNodes()
  if (!sel.length) return
  applyGfvStickerToNodes(sel, id)
}
</script>
