<template>
  <div
    v-show="paletteOpen"
    class="pointer-events-auto fixed right-3 bottom-[220px] z-1001 flex max-h-[min(70vh,440px)] w-[min(calc(100vw-24px),228px)] flex-col overflow-hidden rounded-sm border border-interface-stroke bg-comfy-menu-bg/95 text-sm shadow-interface backdrop-blur-sm"
    data-testid="node-type-color-palette-panel"
    @pointerdown.stop
  >
    <div
      class="flex items-center justify-between gap-2 border-b border-interface-stroke px-2 py-1.5"
    >
      <span class="text-node-component-fg truncate text-xs font-medium">{{
        $t('nodeColorPalette.title')
      }}</span>
      <button
        type="button"
        class="hover:text-node-component-fg rounded-sm p-0.5 text-muted-foreground hover:bg-component-node-background"
        :aria-label="$t('g.close')"
        @click="paletteStore.closePalette()"
      >
        <i class="icon-[lucide--x] size-4" />
      </button>
    </div>

    <p class="px-2 pt-1.5 text-[10px] leading-snug text-muted-foreground">
      {{ $t('nodeColorPalette.hint') }}
    </p>

    <div v-if="anchorType" class="px-2 pb-1 text-[10px] text-muted-foreground">
      <span>{{ $t('nodeColorPalette.nodeTypeLabel') }}</span>
      <code
        class="ml-1 rounded-sm bg-component-node-background px-1 py-px text-[10px]"
        >{{ anchorType }}</code
      >
      <span v-if="savedForType" class="ml-1 text-primary-400">{{
        $t('nodeColorPalette.hasSavedDefault')
      }}</span>
    </div>
    <div
      v-else
      class="px-2 pb-1 text-[10px] text-amber-600 dark:text-amber-400"
    >
      {{ $t('nodeColorPalette.noSelection') }}
    </div>

    <div class="min-h-0 flex-1 overflow-y-auto px-2 pb-2">
      <div class="mb-1.5 text-[10px] font-medium text-muted-foreground">
        {{ $t('nodeColorPalette.presets') }}
      </div>
      <div class="mb-2 grid grid-cols-9 gap-0.5">
        <button
          v-for="sw in presetSwatches"
          :key="sw.presetKey ?? sw.color"
          type="button"
          :disabled="canvasReadOnly"
          class="h-5 min-w-0 rounded-sm border border-interface-stroke/80 ring-offset-1 outline-none focus-visible:ring-2 focus-visible:ring-primary-500 disabled:opacity-40"
          :title="sw.presetKey"
          :style="{
            backgroundColor: sw.bgcolor,
            borderLeftWidth: '3px',
            borderLeftColor: sw.color
          }"
          draggable="true"
          @click="onSwatchClick(sw, $event)"
          @dragstart="onSwatchDragStart(sw, $event)"
        />
      </div>

      <div class="mb-1 text-[10px] font-medium text-muted-foreground">
        {{ $t('nodeColorPalette.grid') }}
      </div>
      <div class="grid grid-cols-8 gap-0.5">
        <button
          v-for="(sw, idx) in generatedSwatches"
          :key="`g-${idx}-${sw.color}`"
          type="button"
          :disabled="canvasReadOnly"
          class="h-5 min-w-0 rounded-sm border border-interface-stroke/80 ring-offset-1 outline-none focus-visible:ring-2 focus-visible:ring-primary-500 disabled:opacity-40"
          :style="{
            backgroundColor: sw.bgcolor,
            borderLeftWidth: '3px',
            borderLeftColor: sw.color
          }"
          draggable="true"
          @click="onSwatchClick(sw, $event)"
          @dragstart="onSwatchDragStart(sw, $event)"
        />
      </div>

      <button
        type="button"
        class="mt-2 w-full rounded-sm border border-interface-stroke px-2 py-1 text-[10px] text-muted-foreground hover:bg-component-node-background disabled:opacity-40"
        :disabled="!anchorType || !savedForType || canvasReadOnly"
        @click="clearSavedDefault"
      >
        {{ $t('nodeColorPalette.clearSaved') }}
      </button>
    </div>
  </div>
</template>

<script setup lang="ts">
import { storeToRefs } from 'pinia'
import { computed } from 'vue'
import { useCanvasStore } from '@/renderer/core/canvas/canvasStore'
import { LGraphCanvas } from '@/lib/litegraph/src/litegraph'
import type { LGraphNode } from '@/lib/litegraph/src/litegraph'
import { app } from '@/scripts/app'
import { useNodeTypeColorStore } from '@/stores/nodeTypeColorStore'
import { useToastStore } from '@/platform/updates/common/toastStore'
import { useI18n } from 'vue-i18n'
import { NODE_COLOR_DRAG_MIME, stringifyNodeColorDragPayload } from '@/utils/nodeColorDrag';
import type { NodeColorDragPayload } from '@/utils/nodeColorDrag';
import { buildGeneratedSwatchGrid, swatchesFromLitegraphPresets } from '@/utils/nodeColorPaletteGrid';
import type { SwatchPair } from '@/utils/nodeColorPaletteGrid';
import { applyNodeColorPair } from '@/utils/nodeColorApply'
import { getSelectedLGraphNodesForPalette } from '@/utils/nodeColorPaletteSelection'

const paletteStore = useNodeTypeColorStore()
const { paletteOpen } = storeToRefs(paletteStore)
const canvasStore = useCanvasStore()
const { selectedItems } = storeToRefs(canvasStore)
const toastStore = useToastStore()
const { t } = useI18n()

const presetSwatches = computed(() =>
  swatchesFromLitegraphPresets(LGraphCanvas.node_colors)
)
const generatedSwatches = computed(() => buildGeneratedSwatchGrid())

const canvasReadOnly = computed(() => app.canvas?.state.readOnly ?? false)

function selectedNodesList(): LGraphNode[] {
  return getSelectedLGraphNodesForPalette(app.canvas)
}

const anchorType = computed(() => {
  // Read selectedItems so this updates when the graph selection changes.
  void selectedItems.value
  return selectedNodesList()[0]?.type || ''
})

const savedForType = computed(() =>
  anchorType.value ? !!paletteStore.getTypeDefault(anchorType.value) : false
)

function applyPairToNodes(
  nodes: LGraphNode[],
  color: string | undefined,
  bgcolor: string | undefined
) {
  for (const n of nodes) {
    applyNodeColorPair(n, color, bgcolor)
  }
  app.canvas?.setDirty(true, true)
}

function onSwatchClick(sw: SwatchPair, e: MouseEvent) {
  if (canvasReadOnly.value) return
  const pair = { color: sw.color, bgcolor: sw.bgcolor }
  if (e.ctrlKey) {
    applyToAllTypeAndSave(pair)
    return
  }
  const sel = selectedNodesList()
  if (!sel.length) {
    toastStore.add({
      severity: 'info',
      summary: t('nodeColorPalette.toastNoSelection'),
      life: 3500
    })
    return
  }
  applyPairToNodes(sel, pair.color, pair.bgcolor)
}

function applyToAllTypeAndSave(pair: { color: string; bgcolor: string }) {
  const type = anchorType.value
  if (!type || !app.canvas?.graph) {
    toastStore.add({
      severity: 'info',
      summary: t('nodeColorPalette.toastNoTypeForBulk'),
      life: 3500
    })
    return
  }
  paletteStore.setTypeDefault(type, pair)
  for (const n of app.canvas.graph.nodes) {
    if (n.type === type) applyNodeColorPair(n, pair.color, pair.bgcolor)
  }
  app.canvas.setDirty(true, true)
}

function onSwatchDragStart(sw: SwatchPair, e: DragEvent) {
  if (canvasReadOnly.value) {
    e.preventDefault()
    return
  }
  const dt = e.dataTransfer
  if (!dt) return
  const payload: NodeColorDragPayload = {
    color: sw.color,
    bgcolor: sw.bgcolor,
    allOfType: e.ctrlKey
  }
  const raw = stringifyNodeColorDragPayload(payload)
  dt.setData(NODE_COLOR_DRAG_MIME, raw)
  dt.setData('text/plain', raw)
  dt.effectAllowed = 'copy'
}

function clearSavedDefault() {
  const type = anchorType.value
  if (!type) return
  paletteStore.clearTypeDefault(type)
}
</script>
