import type { LGraphNode } from '@/lib/litegraph/src/litegraph'
import type { TWidgetValue } from '@/lib/litegraph/src/types/widgets'
import {
  extractVueNodeData,
  type VueNodeData
} from '@/composables/graph/useGraphNodeManager'
import { useVueNodeLifecycle } from '@/composables/graph/useVueNodeLifecycle'
import { app } from '@/scripts/app'
import type { NodeStickerId } from '@/constants/nodeStickers'

/**
 * Persist sticker on LiteGraph properties and sync Vue node data (property bag +
 * graph events are easy to miss in some builds).
 */
export function useNodeStickerApply() {
  const vueNodeLifecycle = useVueNodeLifecycle()

  function applyGfvStickerToNodes(
    nodes: LGraphNode[],
    sticker: NodeStickerId | undefined
  ) {
    const mgr = vueNodeLifecycle.nodeManager.value
    const vuePatch =
      mgr?.vueNodeData as Map<string, VueNodeData> | undefined
    for (const n of nodes) {
      const prev = n.properties?.gfvSticker as string | undefined
      n.setProperty('gfvSticker', sticker as TWidgetValue)
      n.graph?.trigger('node:property:changed', {
        nodeId: n.id,
        property: 'properties.gfvSticker',
        oldValue: prev,
        newValue: sticker
      })
      if (!vuePatch) continue
      const id = String(n.id)
      const cur = vuePatch.get(id)
      if (cur) {
        vuePatch.set(id, {
          ...cur,
          sticker: sticker && String(sticker).length ? String(sticker) : undefined
        })
      } else {
        vuePatch.set(id, extractVueNodeData(n))
      }
    }
    app.canvas?.setDirty(true, true)
  }

  return { applyGfvStickerToNodes }
}
