import type { LGraphCanvas, LGraphNode } from '@/lib/litegraph/src/litegraph'
import { isLGraphNode } from '@/utils/litegraphUtil'

/**
 * Nodes that match the visible graph selection (same source as Vue selection outline).
 * Prefer {@link LGraphCanvas.selectedItems}; fall back to deprecated `selected_nodes`.
 *
 * In Vue, `selectedItems` is a mutated Set — not reactive. Components must depend on
 * {@link useCanvasStore}'s `selectedItems` ref (e.g. `void selectedItems.value` in a
 * computed) so the UI updates when selection changes.
 */
export function getSelectedLGraphNodesForPalette(
  canvas: LGraphCanvas | null | undefined
): LGraphNode[] {
  if (!canvas) return []
  const fromItems = [...canvas.selectedItems].filter(isLGraphNode)
  if (fromItems.length) return fromItems
  const sn = canvas.selected_nodes
  if (sn && Object.keys(sn).length) {
    return Object.values(sn).filter(isLGraphNode)
  }
  // Some paths leave selectedItems / selected_nodes stale; node.selected stays truthy.
  const g = canvas.graph
  if (g?._nodes?.length) {
    return g._nodes.filter((n) => n.selected && isLGraphNode(n))
  }
  return []
}
