import { useColorPaletteStore } from '@/stores/workspace/colorPaletteStore'
import {
  adjustColor,
  contrastingForegroundForBackground,
  relativeLuminance
} from '@/utils/colorUtil'

/**
 * Applies light theme color adjustments to a color
 */
export function applyLightThemeColor(color?: string): string {
  if (!color) return ''

  if (!useColorPaletteStore().completedActivePalette.light_theme) return color

  return adjustColor(color, { lightness: 0.5 })
}

/**
 * CSS variables so header titles, slot labels, and slot dot outlines stay readable
 * on user-chosen node colors (WCAG-style luminance pick).
 */
function foregroundForNodeChrome(background: string): string {
  if (!background) return '#f1f5f9'
  const lum = relativeLuminance(background)
  /* Near-white / light tints: force dark copy for legible chrome on pale nodes. */
  if (lum > 0.86) return '#0a0c12'
  return contrastingForegroundForBackground(background)
}

export function nodeChromeForegroundCssVars(
  headerColorResolved: string,
  bodyColorResolved: string
): Record<string, string> {
  const style: Record<string, string> = {}
  if (headerColorResolved) {
    const fg = foregroundForNodeChrome(headerColorResolved)
    style['--node-component-header'] = fg
    const lum = relativeLuminance(headerColorResolved)
    style['--node-component-header-icon'] =
      lum > 0.45
        ? adjustColor(fg, { lightness: -0.07 })
        : adjustColor(fg, { lightness: 0.1 })
  }
  if (bodyColorResolved) {
    const fg = foregroundForNodeChrome(bodyColorResolved)
    style['--node-component-slot-text'] = fg
    style['--node-component-slot-dot-outline'] = fg
  }
  return style
}
