export const NODE_COLOR_DRAG_MIME = 'application/x-comfy-node-color+json'

export interface NodeColorDragPayload {
  color: string
  bgcolor: string
  /** Set when dragging with Ctrl: on drop, tint all nodes of the target type + persist default. */
  allOfType?: boolean
}

export function stringifyNodeColorDragPayload(p: NodeColorDragPayload): string {
  return JSON.stringify(p)
}

export function parseNodeColorDragPayload(raw: string): NodeColorDragPayload | null {
  try {
    const o = JSON.parse(raw) as NodeColorDragPayload
    if (typeof o.color !== 'string' || typeof o.bgcolor !== 'string') return null
    return o
  } catch {
    return null
  }
}

export function readNodeColorDragFromDataTransfer(
  dt: DataTransfer | null
): NodeColorDragPayload | null {
  if (!dt) return null
  let raw = dt.getData(NODE_COLOR_DRAG_MIME)
  if (!raw) raw = dt.getData('text/plain')
  if (!raw) return null
  return parseNodeColorDragPayload(raw)
}

export function dataTransferHasNodeColorDrag(dt: DataTransfer | null): boolean {
  if (!dt?.types) return false
  return Array.from(dt.types).includes(NODE_COLOR_DRAG_MIME)
}
